# Using the recurrence of _Mikhail Kurkov_ in A394825.
def aList(lim: int) -> list[int]:
    result = [0] * (lim + 1)
    result[0] = 1
    row = [1] * (lim + 1)
    for k in range(1, lim + 1): row[k] += k * row[k - 1]
    for i in range(1, lim + 1):
        old = row[0]
        row[0] = 0
        for k in range(1, lim + 1):
            row[k], old = k * (row[k - 1] + row[k] - old), row[k]
        result[i] = row[i]
    return result
